import { getAllTasks, assignTask, deleteTask, getEmployees } from '../services/api';
import { format } from 'date-fns';

const PriorityBadge = ({ p }) => {
  const s = { High: 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-300', Medium: 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-300', Low: 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-300' };
  return <span className={`px-2.5 py-1 rounded-full text-xs font-medium ${s[p]}`}>{p}</span>;
};

const StatusBadge = ({ s }) => {
  const styles = { 'Pending': 'bg-gray-100 text-gray-600 dark:bg-gray-700 dark:text-gray-300', 'In Progress': 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300', 'Completed': 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-300' };
  return <span className={`px-2.5 py-1 rounded-full text-xs font-medium ${styles[s]}`}>{s}</span>;
};

const ProgressBar = ({ value }) => (
  <div className="flex items-center gap-2">
    <div className="flex-1 h-2 bg-gray-100 dark:bg-gray-700 rounded-full overflow-hidden">
      <div className="h-full bg-indigo-500 rounded-full transition-all" style={{ width: `${value}%` }} />
    </div>
    <span className="text-xs text-gray-500 w-8">{value}%</span>
  </div>
);

export default function AdminTasks() {
  const [tasks, setTasks] = useState([]);
  const [employees, setEmployees] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [search, setSearch] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [filterPriority, setFilterPriority] = useState('');
  const [form, setForm] = useState({ title: '', description: '', assignedTo: '', priority: 'Medium', deadline: '' });

  const fetchAll = async () => {
    setLoading(true);
    try {
      const [tRes, eRes] = await Promise.all([getAllTasks({ search, status: filterStatus, priority: filterPriority }), getEmployees({ status: 'approved' })]);
      setTasks(tRes.data);
      setEmployees(eRes.data);
    } catch { toast.error('Failed to load data'); }
    finally { setLoading(false); }
  };

  useEffect(() => { fetchAll(); }, [search, filterStatus, filterPriority]);

  const handleAssign = async (e) => {
    e.preventDefault();
    try {
      await assignTask(form);
      toast.success('Task assigned successfully!');
      setShowModal(false);
      setForm({ title: '', description: '', assignedTo: '', priority: 'Medium', deadline: '' });
      fetchAll();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed to assign task'); }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this task?')) return;
    try { await deleteTask(id); toast.success('Task deleted'); fetchAll(); }
    catch { toast.error('Delete failed'); }
  };

  return (
    <div className="space-y-5">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-display font-bold text-gray-900 dark:text-white">Tasks</h2>
        <button onClick={() => setShowModal(true)}
          className="px-4 py-2.5 bg-indigo-600 hover:bg-indigo-500 text-white text-sm font-semibold rounded-xl transition">
          + Assign Task
        </button>
      </div>

      <div className="flex gap-3 flex-wrap">
        <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search tasks..."
          className="flex-1 min-w-48 px-4 py-2.5 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl text-sm text-gray-700 dark:text-gray-300 focus:outline-none focus:border-indigo-400" />
        <select value={filterStatus} onChange={e => setFilterStatus(e.target.value)}
          className="px-4 py-2.5 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl text-sm text-gray-700 dark:text-gray-300 focus:outline-none">
          <option value="">All Status</option>
          <option>Pending</option><option>In Progress</option><option>Completed</option>
        </select>
        <select value={filterPriority} onChange={e => setFilterPriority(e.target.value)}
          className="px-4 py-2.5 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl text-sm text-gray-700 dark:text-gray-300 focus:outline-none">
          <option value="">All Priority</option>
          <option>High</option><option>Medium</option><option>Low</option>
        </select>
      </div>

      <div className="bg-white dark:bg-gray-800 rounded-2xl border border-gray-100 dark:border-gray-700 shadow-sm overflow-hidden">
        {loading ? <div className="p-8 text-center text-gray-400">Loading...</div> : tasks.length === 0 ? (
          <div className="p-8 text-center text-gray-400">No tasks found.</div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead className="bg-gray-50 dark:bg-gray-750">
                <tr>{['Title', 'Assigned To', 'Priority', 'Status', 'Progress', 'Deadline', 'Actions'].map(h => (
                  <th key={h} className="px-5 py-3.5 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wide">{h}</th>
                ))}</tr>
              </thead>
              <tbody className="divide-y divide-gray-50 dark:divide-gray-700">
                {tasks.map(task => (
                  <tr key={task._id} className="hover:bg-gray-50 dark:hover:bg-gray-750 transition">
                    <td className="px-5 py-4">
                      <div className="font-medium text-gray-900 dark:text-white">{task.title}</div>
                      {task.description && <div className="text-xs text-gray-400 mt-0.5 truncate max-w-xs">{task.description}</div>}
                    </td>
                    <td className="px-5 py-4 text-gray-600 dark:text-gray-400">{task.assignedTo?.name}</td>
                    <td className="px-5 py-4"><PriorityBadge p={task.priority} /></td>
                    <td className="px-5 py-4"><StatusBadge s={task.status} /></td>
                    <td className="px-5 py-4 w-36"><ProgressBar value={task.progress || 0} /></td>
                    <td className="px-5 py-4 text-gray-500 dark:text-gray-400">{task.deadline ? format(new Date(task.deadline), 'MMM d, yyyy') : '—'}</td>
                    <td className="px-5 py-4">
                      <button onClick={() => handleDelete(task._id)} className="text-red-400 hover:text-red-600 text-xs font-medium transition">Delete</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Assign Task Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-gray-800 rounded-2xl p-7 w-full max-w-lg shadow-2xl">
            <h3 className="font-display font-bold text-xl text-gray-900 dark:text-white mb-5">Assign New Task</h3>
            <form onSubmit={handleAssign} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Title *</label>
                <input required value={form.title} onChange={e => setForm({ ...form, title: e.target.value })}
                  className="w-full px-4 py-2.5 border border-gray-200 dark:border-gray-600 bg-white dark:bg-gray-700 rounded-xl text-sm text-gray-900 dark:text-white focus:outline-none focus:border-indigo-400"
                  placeholder="Task title" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Description</label>
                <textarea value={form.description} onChange={e => setForm({ ...form, description: e.target.value })}
                  rows={3} className="w-full px-4 py-2.5 border border-gray-200 dark:border-gray-600 bg-white dark:bg-gray-700 rounded-xl text-sm text-gray-900 dark:text-white focus:outline-none focus:border-indigo-400 resize-none"
                  placeholder="Task description..." />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Assign To *</label>
                  <select required value={form.assignedTo} onChange={e => setForm({ ...form, assignedTo: e.target.value })}
                    className="w-full px-4 py-2.5 border border-gray-200 dark:border-gray-600 bg-white dark:bg-gray-700 rounded-xl text-sm text-gray-900 dark:text-white focus:outline-none focus:border-indigo-400">
                    <option value="">Select employee</option>
                    {employees.map(e => <option key={e._id} value={e._id}>{e.name}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Priority</label>
                  <select value={form.priority} onChange={e => setForm({ ...form, priority: e.target.value })}
                    className="w-full px-4 py-2.5 border border-gray-200 dark:border-gray-600 bg-white dark:bg-gray-700 rounded-xl text-sm text-gray-900 dark:text-white focus:outline-none focus:border-indigo-400">
                    <option>Low</option><option>Medium</option><option>High</option>
                  </select>
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Deadline</label>
                <input type="date" value={form.deadline} onChange={e => setForm({ ...form, deadline: e.target.value })}
                  className="w-full px-4 py-2.5 border border-gray-200 dark:border-gray-600 bg-white dark:bg-gray-700 rounded-xl text-sm text-gray-900 dark:text-white focus:outline-none focus:border-indigo-400" />
              </div>
              <div className="flex gap-3 pt-2">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-2.5 border border-gray-200 dark:border-gray-600 text-gray-600 dark:text-gray-400 rounded-xl text-sm font-medium hover:bg-gray-50 dark:hover:bg-gray-700 transition">Cancel</button>
                <button type="submit" className="flex-1 py-2.5 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl text-sm font-semibold transition">Assign Task</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
